INSERT INTO public.theory_quiz_bank (course_id, question, reference_answer) VALUES
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Define data. What is the difference between data and information?', 'Data are raw, unprocessed facts and figures without context (e.g., "25"). Information is data that has been processed, organized, and given context to make it meaningful and useful (e.g., "The customer is 25 years old").'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is a dataset? Name its two primary components.', 'A dataset is a collection of related data. Its two primary components are entities (rows/observations) and attributes (columns/features/variables).'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Define a variable/attribute in the context of a dataset.', 'A variable or attribute is a characteristic or property of an object or entity being recorded. For example, ''height'', ''age'', or ''color''.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Define an observation/record/instance. Provide an example.', 'An observation (or record/instance) is a single entity or data point in a dataset, containing a collection of values for each attribute. Example: One specific person''s details in a customer table.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is the difference between structured and unstructured data?', 'Structured data has a predefined format and resides in fixed fields within a record or file (like tables). Unstructured data has no predefined format or organization, making it difficult to process with traditional tools.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Give three examples of structured data.', 'Three examples: 1) Spreadsheets (Excel files), 2) Relational database tables (SQL), 3) CSV files.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Give three examples of unstructured data.', 'Three examples: 1) Text documents (Word, PDFs), 2) Images (JPEG, PNG), 3) Video and audio files.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is semi-structured data? Provide an example (e.g., JSON, XML).', 'Semi-structured data has some organizational properties (like tags or markers) to separate data elements, but does not conform to a rigid table structure. Example: JSON or XML data, which is self-describing.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Define qualitative data. What are its main sub-types?', 'Qualitative (or categorical) data describes qualities or categories that cannot be measured numerically. Its main sub-types are nominal and ordinal.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Define nominal data. Give an example where arithmetic operations are meaningless.', 'Nominal data is categorical data with no inherent order or ranking. Arithmetic operations are meaningless because the values are just labels. Example: Hair color (Blonde, Brown, Black), Gender.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Define ordinal data. Give an example where order matters but the difference between values does not.', 'Ordinal data is categorical data with a clear, meaningful order, but the intervals between values are not known or equal. Example: Education level (High School, Bachelor''s, Master''s, PhD) or customer satisfaction ratings (Poor, Fair, Good, Excellent).'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Define quantitative data. What are its main sub-types?', 'Quantitative (or numerical) data represents measurements or counts and can be subjected to arithmetic operations. Its main sub-types are interval and ratio.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Define interval data. Give an example where zero is not absolute (e.g., temperature in Celsius).', 'Interval data is numerical data where the difference between values is meaningful, but there is no true zero point. Example: Temperature in Celsius or Fahrenheit (0°C does not mean ''no temperature'').'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Define ratio data. Give an example where a true zero point exists (e.g., height, weight).', 'Ratio data is numerical data with a meaningful difference between values and a true, absolute zero point, allowing for ratio comparisons. Example: Height, weight, age, income (0 means none of the quantity).'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is a discrete variable? Provide an example.', 'A discrete variable is a variable whose values are countable and typically integers. Example: Number of children in a family, number of cars sold.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is a continuous variable? Provide an example.', 'A continuous variable is a variable that can take on any value within a given range (can be measured, not just counted). Example: Height (1.75m, 1.751m), weight, temperature.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is data preprocessing? Why is it necessary?', 'Data preprocessing is the process of transforming raw data into an understandable and clean format. It is necessary because real-world data is often incomplete, inconsistent, and/or lacking in certain behaviors or trends, which can lead to inaccurate models.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Define data cleaning. List two common tasks involved.', 'Data cleaning is the process of detecting and correcting (or removing) corrupt, inaccurate, or irrelevant records from a dataset. Two common tasks: handling missing values and smoothing noisy data.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is missing data? Name two common strategies for handling it.', 'Missing data occurs when no data value is stored for a variable in an observation. Two common strategies: 1) Remove records with missing values, 2) Impute (fill in) missing values using the mean, median, or mode of the column.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is data transformation? Give an example, such as normalization.', 'Data transformation is the process of converting data from one format or structure to another. Example: Normalization (scaling numerical data to fit within a specific range, like 0 to 1).'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is data integration? What is a primary challenge associated with it (e.g., entity identification)?', 'Data integration is the process of combining data from different sources into a single, unified view. A primary challenge is entity identification (matching the same real-world entity from different sources).'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is data reduction? Why might it be used on a large dataset?', 'Data reduction is the process of obtaining a reduced representation of a dataset that is much smaller in volume but produces the same (or almost the same) analytical results. It is used to improve storage efficiency and reduce processing time.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Define a data warehouse.', 'A data warehouse is a large, centralized repository of data that is used for reporting and data analysis. It typically stores historical data integrated from multiple sources in a structured, optimized format for querying.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is the difference between a data warehouse and a data lake?', 'A data warehouse stores processed, structured data for specific business purposes (schema-on-write). A data lake stores vast amounts of raw data in its native format (structured, semi-structured, unstructured) until it is needed (schema-on-read).'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Define metadata. Why is it important?', 'Metadata is "data about data." It provides information about other data, such as its source, format, creation date, author, and meaning. It is important for data discovery, governance, and understanding the context of the data.');